What does this program print?

```cpp
#include <iostream>
#include <stdexcept>
int main() {
    try {
        throw std::invalid_argument("bad");
    } catch (const std::runtime_error& e) {
        std::cout << "runtime\n";
    } catch (const std::invalid_argument& e) {
        std::cout << "invalid\n";
    }
    std::cout << "end\n";
    return 0;
}
```

What does this program print?

```cpp
#include <iostream>
#include <stdexcept>
void f() { throw std::runtime_error("err"); }
int main() {
    try {
        f();
        std::cout << "after f\n";
    } catch (const std::runtime_error& e) {
        std::cout << e.what() << "\n";
    }
    std::cout << "done\n";
    return 0;
}
```
